import math

def draw_analog_dial(value, min_val=0, max_val=100, radius=10):
    # Calculate pointer position
    angle = math.radians(180 - (value / (max_val - min_val)) * 180)
    x = int(radius * math.cos(angle))
    y = int(radius * math.sin(angle))

    # Draw the dial
    for i in range(-radius, radius + 1):
        for j in range(-radius, radius + 1):
            dist = math.sqrt(i**2 + j**2)
            if dist > radius:
                print(' ', end='')
            elif dist < radius - 1:
                print('.', end='')
            else:
                if i == x and j == y:
                    print('>', end='')  # Pointer
                else:
                    print('|', end='')
        print()

# Example usage: draw_analog_dial(75, 0, 100, 10)

This function draws a circular dial with a pointer (represented by '>') indicating the given value. The scale is simplified for ASCII rendering, and the pointer's position is calculated based on the input value.
